import React, { useState, useEffect } from 'react';
import { View, Text, Button } from 'react-native';
import axios from 'axios';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);

  const clientId = 'YOUR_CLIENT_ID';
  const clientSecret = 'YOUR_CLIENT_SECRET';
  const redirectUri = 'YOUR_REDIRECT_URI';

  useEffect(() => {
    // Check if there's a stored access token
    const storedAccessToken = localStorage.getItem('accessToken');
    const storedRefreshToken = localStorage.getItem('refreshToken');

    if (storedAccessToken && storedRefreshToken) {
      setAccessToken(storedAccessToken);
      setRefreshToken(storedRefreshToken);
    } else {
      // If no tokens, initiate the OAuth flow
      initiateOAuthFlow();
    }
  }, []);

  const initiateOAuthFlow = async () => {
    try {
      const response = await axios.get('https://your-oauth-server.com/auth/authorize', {
        params: {
          client_id: clientId,
          redirect_uri: redirectUri,
          response_type: 'code',
          scope: 'openid profile email'
        }
      });

      // Handle the authorization code and exchange for tokens
      const { code } = response.data;
      await exchangeCodeForTokens(code);
    } catch (error) {
      console.error('OAuth flow failed:', error);
    }
  };

  const exchangeCodeForTokens = async (code) => {
    try {
      const response = await axios.post('https://your-oauth-server.com/auth/token', null, {
        params: {
          client_id: clientId,
          client_secret: clientSecret,
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: redirectUri
        }
      });

      const { access_token, refresh_token } = response.data;
      setAccessToken(access_token);
      setRefreshToken(refresh_token);

      // Store tokens in local storage for persistence
      localStorage.setItem('accessToken', access_token);
      localStorage.setItem('refreshToken', refresh_token);

      // Set up token refresh interval
      setInterval(refreshTokens, 3600000); // Refresh every hour
    } catch (error) {
      console.error('Token exchange failed:', error);
    }
  };

  const refreshTokens = async () => {
    try {
      const response = await axios.post('https://your-oauth-server.com/auth/token', null, {
        params: {
          client_id: clientId,
          client_secret: clientSecret,
          grant_type: 'refresh_token',
          refresh_token: refreshToken
        }
      });

      const { access_token } = response.data;
      setAccessToken(access_token);

      // Update stored token
      localStorage.setItem('accessToken', access_token);
    } catch (error) {
      console.error('Token refresh failed:', error);
    }
  };

  const handleLogout = () => {
    setAccessToken(null);
    setRefreshToken(null);
    localStorage.removeItem('accessToken');
    localStorage.removeItem('refreshToken');
  };

  return (
    <View>
      {accessToken ? (
        <>
          <Text>Welcome!</Text>
          <Button title="Logout" onPress={handleLogout} />
        </>
      ) : (
        <Text>Loading...</Text>
      )}
    </View>
  );
};

export default App;